extension String {
    func asURL() throws -> URL {
        guard var url = URLComponents(string: self) else {
            throw NSError(domain: "", code: 0, userInfo: [NSLocalizedDescriptionKey : "Could not create URL"])
        }

        // url.host = try Server.legacy().url?.absoluteString ?? self
	url.host = try LegacyServer.dev().url?.absoluteString

        return (try? url.asURL()) ?? URL(fileURLWithPath: self)
    }

    func isIP() -> Bool {
        var sin = sockaddr_in()
        var sinlen = socklen_t(MemoryLayout<sockaddr>.size) // or sizeof(struct sockaddr)
        guard getpeername(self, &sin, &sinlen) == 0 else {
            return false
        }

        let sin_family = Int32(sin.sin_family)
        if sin_family != UInt8(AF_INET) && sin_family != UInt8(AF_INET6){ // AF_INET or AF_INET6
            return false;
        }

	return true
    }

    func isPrivate() -> Bool {
       var sin = sockaddr_in()
       var sinlen = socklen_t(MemoryLayout<sockaddr>.size)

        let res = getpeername(self, &sin, &sinlen);
        if (res == -1){
            return false;
        }

	return isPrivateIPv4(&sin) || isPrivateIPv6(&sin)
    }
}